const loopData = $('Credentials Loop').item.json;
const timestamp = new Date().toISOString();

const logLine = `[${timestamp}] MISSING: No se encontró ${loopData.fileName} en ${loopData.fullPath}\n`;

return {
  json: {
    logLine,
    logPath: loopData.logPath
  }
};

const fileContent = $json.text;
const lines = fileContent.split('\n');
const matches = [];

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;

  const spaceIdx = trimmed.indexOf(' ');
  if (spaceIdx === -1) continue;

  const kb = parseInt(trimmed.substring(0, spaceIdx), 10);
  if (isNaN(kb) || kb <= 500) continue;

  const path = trimmed.substring(spaceIdx + 1).trim();
  const parts = path.split('\\');

  // Requiere estructura con carpeta de versión: [..., nombre_carpeta, version, nombre.rpt]
  if (parts.length < 7) continue;

  const version = parseInt(parts[5], 10);
  const nombreRpt = parts[6].trim();

  // Versión debe ser entero positivo
  if (isNaN(version) || version <= 0) continue;

  // Solo archivos .rpt reales (sin sufijos extra como .rpt20210201 o .rptfb)
  if (!nombreRpt.toLowerCase().endsWith('.rpt')) continue;

  matches.push({ kb, version, nombreRpt });
}

return {
  json: {
    matches,
    hasMatches: matches.length > 0
  }
};

const sqlResults = $json.sqlResults;
const resultFileName = $('Credentials Loop').item.json.resultFileName;

const headers = ['CuitId','RazonSocial','PuntoDeVentaId','TipoComprobanteId','VersionRpt','NombreRpt','FechaSubida','UsuarioId'];
const rows = sqlResults.map(r =>
  headers.map(h => `"${(r[h] ?? '').toString().replace(/"/g, '""')}"`).join(';')
);
const csvContent = [headers.join(';'), ...rows].join('\n');

return [{
  json: { ...$json },
  binary: {
    data: {
      data: Buffer.from(csvContent, 'utf8').toString('base64'),
      mimeType: 'text/csv',
      fileExtension: 'csv',
      fileName: resultFileName
    }
  }
}];

// Expande el array de entornos en items individuales para el loop
const envs = $input.first().json.environments;
return envs.map(e => ({ json: e }));

// Filtra .rpt con peso > 100kb y agrega el entorno de origen
const ONE_HUNDRED_KB = 100 * 1024;
const envName = $('Loop Entornos').first().json.env;

const heavy = $input.all()
  .filter(item => {
    const f = item.json;
    return f.type === '-' && f.name.toLowerCase().endsWith('.rpt') && f.size > ONE_HUNDRED_KB;
  })
  .sort((a, b) => a.json.modifyTime - b.json.modifyTime)
  .map(item => ({
    json: {
      env: envName,
      name: item.json.name,
      sizeKb: Math.round(item.json.size / 1024),
      date: new Date(item.json.modifyTime).toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' })
    }
  }));

return heavy;

// Agrupa todos los archivos pesados de todos los entornos
const all = $input.all();
if (all.length === 0) return [];

const fileRows = all.map(item => {
  const f = item.json;
  return `<li>[${f.env}] <b>${f.name}</b> — ${f.sizeKb} KB — ${f.date}</li>`;
}).join('');

return [{ json: { count: all.length, fileRows } }];

const { matches, env, dateSuffix } = $json;

const validos = matches.filter(r => r.version !== null && r.version !== undefined);

if (validos.length === 0) {
  return { json: { ...$json, sqlQuery: null } };
}

const valuesList = validos
  .map(r => `        ('${r.nombreRpt.replace(/'/g, "''")}', ${r.version})`)
  .join(',\n');

const sql =
  `SELECT c.CuitId, c.RazonSocial, t.PuntoDeVentaId, t.TipoComprobanteId, ` +
  `t.VersionRpt, t.NombreRpt, a.FechaSubida, a.UsuarioId\n` +
  `FROM TipoComprobanteXPuntoDeVenta t\n` +
  `INNER JOIN VersionReporte a ON t.VersionRpt=a.VersionId AND t.NombreRpt=a.NombreRpt\n` +
  `INNER JOIN Cuit c ON t.CuitId = c.CuitId\n` +
  `INNER JOIN (VALUES\n${valuesList})\n` +
  `v(NombreRpt, VersionId) ON a.NombreRpt=v.NombreRpt AND a.VersionId=v.VersionId\n` +
  `WHERE c.FechaBajaServicio IS NULL;`;

return { json: { ...$json, sqlQuery: sql } };
